function bookmarkPageTextJsonData(){const nodeFilter={acceptNode:function(node){const isTextNode=node.nodeType===Node.TEXT_NODE;const isImageElement=node.nodeType===Node.ELEMENT_NODE&&node.tagName==="IMG";const element=isTextNode?node.parentElement:node;if(!element)return NodeFilter.FILTER_REJECT;if(element.closest("script, style, video, audio")){return NodeFilter.FILTER_REJECT}const computedStyle=window.getComputedStyle(element);if(computedStyle.display==="none"||computedStyle.opacity==="0"){return NodeFilter.FILTER_REJECT}if(computedStyle.visibility==="hidden"){return NodeFilter.FILTER_SKIP}if(isTextNode||isImageElement){return NodeFilter.FILTER_ACCEPT}return NodeFilter.FILTER_SKIP}};const walker=document.createTreeWalker(document.body,NodeFilter.SHOW_ELEMENT|NodeFilter.SHOW_TEXT,nodeFilter);const viewportRect=getViewportRect();let fullRange=null;let fullText="";let node;while(node=walker.nextNode()){const isTextNode=node.nodeType===Node.TEXT_NODE;if(isTextNode){if(!node.textContent.trim()){fullText+=node.textContent;continue}const range=document.createRange();range.setStart(node,0);range.setEnd(node,node.length);const intersection=getIntersectionPercentage(viewportRect,getNonZeroBoundingClientRect(range));if(intersection>0){if(intersection>=1){if(!fullRange){fullRange=document.createRange();fullRange.setStart(node,0)}fullRange.setEnd(node,node.length);fullText+=node.nodeValue}else{const partialRange=getPartiallyVisibleRange(range,viewportRect,.5,false);if(partialRange){if(!fullRange){fullRange=document.createRange();fullRange.setStart(partialRange.startContainer,partialRange.startOffset)}fullRange.setEnd(partialRange.endContainer,partialRange.endOffset);fullText+=partialRange.toString()}}}else if(fullRange){break}}else{let rect=getNonZeroBoundingClientRect(node);if(isIntersecting(viewportRect,rect)){if(!fullRange){fullRange=document.createRange();fullRange.setStartBefore(node)}fullRange.setEndAfter(node);fullText+="(이미지)"}else if(fullRange){break}}}const obj={cfi:"",text:fullText.trim(),position:pagePosition()};return JSON.stringify(obj)}const positionOffset=.1;function pagePosition(){let position=0;if(isScrollMode()){const scrollHeight=document.scrollingElement.scrollHeight;if(scrollHeight>0){const clientHeight=getClientHeight();const scrollTop=document.scrollingElement.scrollTop;const offset=Math.min(1,clientHeight/scrollHeight)*positionOffset;position=Math.min(1,Math.max(0,scrollTop/scrollHeight+offset))}}else{const scrollWidth=document.scrollingElement.scrollWidth;if(scrollWidth>0){const columnCount=getColumnCount();const clientWidth=columnCount>1?getClientWidth()/columnCount:getClientWidth();const scrollLeft=document.scrollingElement.scrollLeft;const offset=Math.min(1,clientWidth/scrollWidth)*positionOffset;position=Math.min(1,Math.max(0,scrollLeft/scrollWidth+offset))}}return position}const bookmarkOverlayDivClassName="kakaopage_bookmark-id";let bookmarkVisibilityObserver=null;function addBookmark(bookmarkId,position){removeBookmark(bookmarkId);const element=createBookmarkElement(bookmarkId,position);document.body.appendChild(element)}function createBookmarkElement(bookmarkId,position){const viewportRect=getViewportRect();const safePosition=Math.min(1,Math.max(0,position));let rect;if(isScrollMode()){const scrollHeight=document.scrollingElement.scrollHeight;const offset=scrollHeight>0?Math.min(1,viewportRect.height/scrollHeight)*positionOffset:0;const top=scrollHeight*(safePosition-offset);const height=Math.min(viewportRect.height,scrollHeight-top);rect=new DOMRect(0,top,viewportRect.width,height)}else{const scrollWidth=document.scrollingElement.scrollWidth;const columnCount=getColumnCount();const clientWidth=columnCount>1?viewportRect.width/columnCount:viewportRect.width;const left=clientWidth>0?Math.floor(scrollWidth*safePosition/clientWidth)*clientWidth:0;rect=new DOMRect(Math.min(left,scrollWidth-clientWidth),0,clientWidth,viewportRect.height)}const element=createOverlayDivElementInRect(rect,"absolute",`${bookmarkOverlayDivClassName}${bookmarkId}`);if(!bookmarkVisibilityObserver){bookmarkVisibilityObserver=new IntersectionObserver(entries=>{entries.forEach(entry=>{const bookmarkId=parseInt(entry.target.className.replace(bookmarkOverlayDivClassName,""),10);if(entry.isIntersecting){if(window.webkit&&window.webkit.messageHandlers.bookmarkDidAppear){window.webkit.messageHandlers.bookmarkDidAppear.postMessage(bookmarkId)}}else{if(window.webkit&&window.webkit.messageHandlers.bookmarkDidDisappear){window.webkit.messageHandlers.bookmarkDidDisappear.postMessage(bookmarkId)}}})},{threshold:.5})}bookmarkVisibilityObserver.observe(element);return element}function removeBookmark(bookmarkId){const idSelector=bookmarkId?`[class*="${bookmarkId}"]`:"";const existing=document.querySelectorAll(`div[class*="${bookmarkOverlayDivClassName}"]${idSelector}`);existing.forEach(element=>{if(bookmarkVisibilityObserver){bookmarkVisibilityObserver.unobserve(element)}element.remove();if(window.webkit&&window.webkit.messageHandlers.bookmarkDidDisappear){const removedId=bookmarkId??parseInt(element.className.replace(bookmarkOverlayDivClassName,""),10);if(removedId){window.webkit.messageHandlers.bookmarkDidDisappear.postMessage(removedId)}}})}function removeAllBookmarks(){removeBookmark(null)}